 {"id":"bd-1jsq","title":"Implement LogRing bounded circular buffer","description":"# Implement LogRing bounded circular buffer

## Background
Part of Progressive Rendering (bd-3t87). Memory-efficient storage for log lines that evicts oldest when full.

## Technical Design

```rust
use std::collections::VecDeque;

/// Circular buffer for log storage
pub struct LogRing<T> {
    /// Circular buffer
    ring: VecDeque<T>,

    /// Maximum capacity
    capacity: usize,

    /// Total items ever added (for accurate indexing)
    total_count: usize,

    /// Optional overflow file for persistence
    overflow: Option<OverflowFile>,
}

impl<T> LogRing<T> {
    pub fn new(capacity: usize) -> Self {
        Self {
            ring: VecDeque::with_capacity(capacity),
            capacity,
            total_count: 0,
            overflow: None,
        }
    }

    pub fn with_overflow(mut self, path: impl AsRef<Path>) -> io::Result<Self> {
        self.overflow = Some(OverflowFile::new(path)?);
        Ok(self)
    }

    /// Add item to ring
    pub fn push(&mut self, item: T) {
        self.total_count += 1;

        if self.ring.len() >= self.capacity {
            let evicted = self.ring.pop_front();

            // Write to overflow if configured
            if let (Some(overflow), Some(item)) = (&mut self.overflow, evicted) {
                overflow.write(&item);
            }
        }

        self.ring.push_back(item);
    }

    /// Add multiple items efficiently
    pub fn extend(&mut self, items: impl Iterator<Item = T>) {
        for item in items {
            self.push(item);
        }
    }

    /// Get item by absolute index (across entire history)
    pub fn get(&self, absolute_idx: usize) -> Option<&T> {
        let ring_start = self.total_count.saturating_sub(self.ring.len());

        if absolute_idx >= ring_start && absolute_idx < self.total_count {
            // In ring
            self.ring.get(absolute_idx - ring_start)
        } else if absolute_idx < ring_start {
            // In overflow (if available)
            None  // Would need to read from overflow file
        } else {
            None
        }
    }

    /// Get range of items
    pub fn get_range(&self, range: Range<usize>) -> Vec<&T> {
        range.filter_map(|i| self.get(i)).collect()
    }

    /// Total items ever added
    pub fn total_count(&self) -> usize {
        self.total_count
    }

    /// Items currently in memory
    pub fn len(&self) -> usize {
        self.ring.len()
    }

    /// First index still in memory
    pub fn first_index(&self) -> usize {
        self.total_count.saturating_sub(self.ring.len())
    }

    /// Last index (most recent)
    pub fn last_index(&self) -> usize {
        self.total_count.saturating_sub(1)
    }

    /// Clear all items
    pub fn clear(&mut self) {
        self.ring.clear();
        // Note: total_count preserved for consistency
    }

    /// Iterate over items in memory
    pub fn iter(&self) -> impl Iterator<Item = &T> {
        self.ring.iter()
    }
}

/// Overflow file for persisted logs
struct OverflowFile {
    file: BufWriter<File>,
    index: Vec<u64>,  // Byte offset for each line
}

impl OverflowFile {
    fn new(path: impl AsRef<Path>) -> io::Result<Self> {
        let file = BufWriter::new(File::create(path)?);
        Ok(Self {
            file,
            index: Vec::new(),
        })
    }

    fn write<T: Serialize>(&mut self, item: &T) {
        // Record position
        self.index.push(self.file.stream_position().unwrap_or(0));

        // Write JSON line
        if let Ok(json) = serde_json::to_string(item) {
            writeln!(self.file, "{}", json).ok();
        }
    }
}
```

## Performance Characteristics
- Push: O(1) amortized
- Get (in ring): O(1)
- Get (in overflow): O(1) file seek + read
- Memory: O(capacity)

